// T108 GroupBookingCoordinatorHandler — CORRECT all-or-nothing pattern
async coordinateGroupBooking(input: GroupInput): Promise<DataProcessResult<GroupResult>> {
  // ALL issuances in ONE transaction — atomic rollback if any member fails
  const result = await this.db.transaction(async () => {
    const issuedTickets: Record<string, unknown>[] = [];
    for (const member of input.members) {
      const ticket = await this.issueTicket({ memberId: member.userId, eventId: input.eventId });
      if (!ticket.isSuccess) throw new Error(`Member ${member.userId} ticket issuance failed`);
      issuedTickets.push(ticket.data as Record<string, unknown>);
    }
    return issuedTickets;
  });
  // DNA-8: storeDocument BEFORE GroupBookingCompleted
  await this.db.storeDocument('group-bookings', { groupId: input.groupId, status: 'CONFIRMED', knowledgeScope: 'PRIVATE' }, input.groupId);
  await this.queue.enqueue('group.booking.completed', { groupId: input.groupId });
  return DataProcessResult.success({ groupId: input.groupId, ticketCount: result.length });
}
